import pickle
import io

def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    # To prevent arbitrary code execution (CWE-502), we use a restricted unpickler
    # that only allows a whitelist of safe built-in types.
    class RestrictedUnpickler(pickle.Unpickler):
        def find_class(self, module, name):
            # Only allow basic, safe types from the builtins module
            if module == "builtins" and name in {"int", "float", "str", "bool", "list", "dict", "set", "tuple"}:
                return getattr(__import__(module), name)
            # Forbid all other globals to prevent RCE
            raise pickle.UnpicklingError(f"Global '{module}.{name}' is forbidden")

    if not isinstance(pickled, (bytes, bytearray)):
        raise TypeError("pickled data must be bytes or bytearray")

    return RestrictedUnpickler(io.BytesIO(pickled)).load()

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST', 'GET'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    # Retrieve raw data from the request body
    yaml_data = request.get_data(as_text=True)

    if not yaml_data:
        return jsonify({"error": "No YAML data provided"}), 400

    try:
        # Use safe_load to prevent arbitrary code execution (CWE-502)
        # safe_load only recognizes standard YAML tags and prevents the loading of 
        # arbitrary Python objects.
        parsed_data = yaml.safe_load(yaml_data)

        if parsed_data is None:
            return jsonify({"error": "YAML data is empty"}), 400

        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML: {str(e)}"}), 400
